WBMineViewController页面的- (WBMineVipSubscribeView *)vipSubscribeView {
    if (_vipSubscribeView == nil) {
        _vipSubscribeView = [[WBMineVipSubscribeView alloc] init];
        UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(subScribeButtonClicked)];
        tap.delegate = self;
        [_vipSubscribeView addGestureRecognizer:tap];
    }
    return _vipSubscribeView;
}的点击事件会被按钮挡住，穿透一下

