- (void)contactCustomerService:(NSString * _Nullable)keyword {
    WBSettingManager.sharedManager.HasNewMessage = FALSE;
    PostNotificationOnMainThread(WBUserMsgStatusUpdateNotification, nil);

    UIViewController *visibleVC = self.navigationController.visibleViewController;
    if ([visibleVC isKindOfClass:[WBFeedbackViewController class]]) {
        WBFeedbackViewController *feedbackVC = (WBFeedbackViewController *)visibleVC;
        [feedbackVC onRoutedWithKeyword:keyword];
    } else {
        NSParameterAssert(visibleVC == self);
        WBFeedbackViewController *feedbackVC = [[WBFeedbackViewController alloc] init];
        [self.navigationController pushViewController:feedbackVC animated:YES];
        [feedbackVC onRoutedWithKeyword:keyword];
    }
}

