+ (void)shareApp {
    WBSettingManager.sharedManager.HasNewShare = false;
    [[WBAppManager sharedManager] shareApp];
    [WBSharePopViewController alertToShare];
}

- (void)showUpdateAlertWithUpdateInfo:(NSDictionary *)updateInfo shouldUpdate:(BOOL)shouldUpdate {
    NSString *titleString = shouldUpdate ? @"App Store有新版本可用" : @"当前已是最新版本";
    NSString *contentString = shouldUpdate ? @"\n有新版本可用，建议前往App Store进行更新，以获得更好的产品体验" : @"\n无需更新";
    UIAlertController *alertController = [UIAlertController alertControllerWithTitle:titleString message:contentString preferredStyle:UIAlertControllerStyleAlert];

    if (shouldUpdate) {
        NSNumber *tidNum = [updateInfo[@"trackId"] isKindOfClass:[NSNumber class]] ? updateInfo[@"trackId"] : nil;
        NSString *tid = tidNum ? tidNum.stringValue : nil;

        UIAlertAction *laterAction = [UIAlertAction actionWithTitle:@"稍后再说" style:UIAlertActionStyleDefault handler:nil];
        [alertController addAction:laterAction];
        [laterAction setValue:[UIColor grayColor] forKey:@"titleTextColor"];
        UIAlertAction *updateAction = [UIAlertAction actionWithTitle:@"前往更新" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            if (tid) {
                [WBAppManager.sharedManager viewAppDetailInAppStore:tid];
            } else {
                [SVProgressHUD showErrorWithStatus:@"跳转地址错误"];
            }
        }];
        [alertController addAction:updateAction];
    } else {
        UIAlertAction *iknowAction = [UIAlertAction actionWithTitle:@"我知道了" style:UIAlertActionStyleDefault handler:nil];
        [alertController addAction:iknowAction];
    }

    [[WBAppManager getUIApplicationCurrentViewController] presentViewController:alertController animated:YES completion:nil];
}


#pragma mark - WBMineFunctionViewDelegate

- (void)functionView:(WBMineFunctionView *)functionView didSelectItemAtIndex:(NSInteger)index {
    UIViewController *targetVC = nil;
    BOOL shouldPush = YES;

    switch (index) {
        case 0: { // 设置
            targetVC = [[WBSettingGlobalViewController alloc] init];
            break;
        }
        case 1: { // 优惠券
            WBSettingManager.sharedManager.HasNewPromo = FALSE;
            [self.functionView updateDynamicDataForFunctionType:@"promo" showNotice:NO tipString:@""];
            [[UIApplication sharedApplication] sendAction:NSSelectorFromString(@"updateTabbarBadge") to:nil from:self forEvent:nil];
            targetVC = [[WBPromoViewController alloc] init];
            break;
        }
        case 2: { // 客服反馈
            [[WBAppManager sharedManager] customerServiceButtonClick];
            shouldPush = NO;
            break;
        }
        case 3: { // 关于
            targetVC = [[WBAboutViewController alloc] init];
            break;
        }
        case 4: { // 检查更新
            WBSettingManager.sharedManager.HasUpdate = FALSE;
            [self.functionView updateDynamicDataForFunctionType:@"update" showNotice:NO tipString:@""];
            [WBAppManager.sharedManager checkUpdateWithCompletion:^(BOOL found, BOOL shouldUpdate, NSDictionary *updateInfo) {
                if (found) {    // 应用在架
                    [self showUpdateAlertWithUpdateInfo:updateInfo shouldUpdate:shouldUpdate];
                } else {    // 应用不在架
                    [WBEventManager logAppCheckUpdateButtonClickEvent];
                }
            }];
            shouldPush = NO;
            break;
        }
        case 5: { // 分享朋友
            [WBMineViewController shareApp];
            shouldPush = NO;
            break;
        }
        default:
            shouldPush = NO;
            break;
    }

    if (shouldPush && targetVC) {
        [self.navigationController pushViewController:targetVC animated:YES];
    }
}


